const t = $input.item.json;
const segments = Array.isArray(t.segments) ? t.segments : [];
const fullText = t.text || segments.map(s => (s.text || '').trim()).join(' ');

function fmt(sec) {
	const ms = Math.round(sec * 1000);
	const h = Math.floor(ms / 3600000);
	const m = Math.floor((ms % 3600000) / 60000);
	const s = Math.floor((ms % 60000) / 1000);
	const mil = ms % 1000;
	const pad = (n, w = 2) => String(n).padStart(w, '0');
	return `${pad(h)}:${pad(m)}:${pad(s)},${pad(mil, 3)}`;
}

let srt = '';
segments.forEach((seg, i) => {
	srt += `${i + 1}\n${fmt(seg.start)} --> ${fmt(seg.end)}\n${(seg.text || '').trim()}\n\n`;
});
if (!srt) {
	srt = `1\n00:00:00,000 --> 00:00:10,000\n${fullText}\n\n`;
}

const toBin = (text, mimeType, ext, fileName) => ({
	data: Buffer.from(text, 'utf8').toString('base64'),
	mimeType,
	fileExtension: ext,
	fileName,
});

return {
	json: {
		fullText,
		segments,
		duration: t.duration || (segments.length ? segments[segments.length - 1].end : null),
		language: t.language || null,
	},
	binary: {
		txt: toBin(fullText, 'text/plain', 'txt', 'transcript.txt'),
		srt: toBin(srt, 'application/x-subrip', 'srt', 'transcript.srt'),
	},
};

const raw = $input.first().json;
let text = '';
if (raw && raw.output && Array.isArray(raw.output) && raw.output[0] && Array.isArray(raw.output[0].content) && raw.output[0].content[0]) {
	text = raw.output[0].content[0].text || '';
} else if (typeof raw.content === 'string') {
	text = raw.content;
} else if (raw.message && typeof raw.message.content === 'string') {
	text = raw.message.content;
} else if (typeof raw.text === 'string') {
	text = raw.text;
} else {
	text = JSON.stringify(raw);
}

text = text.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
let parsed = { clips: [] };
try { parsed = JSON.parse(text); } catch { parsed = { clips: [] }; }
const clipsIn = Array.isArray(parsed.clips) ? parsed.clips : [];
const duration = Number($('Generate Transcript Files').first().json.duration) || 999999;

const out = [];
const used = [];
for (let i = 0; i < clipsIn.length; i++) {
	const c = clipsIn[i];
	let start = Math.max(0, Number(c.start_sec) || 0);
	let end = Math.min(duration, Number(c.end_sec) || start);
	if (end - start < 15) end = Math.min(duration, start + 20);
	if (end - start > 90) end = start + 90;
	if (end <= start) continue;
	if (used.some(u => start < u.end && end > u.start)) continue;
	used.push({ start, end });
	const id = (c.id || `c${String(i + 1).padStart(2, '0')}`).toLowerCase().replace(/[^a-z0-9]/g, '');
	out.push({
		json: {
			id,
			start_sec: Math.round(start * 1000) / 1000,
			end_sec: Math.round(end * 1000) / 1000,
			duration_sec: Math.round((end - start) * 1000) / 1000,
			title: String(c.title || id),
			hook: String(c.hook || ''),
			tiktok_caption: String(c.tiktok_caption || ''),
			instagram_caption: String(c.instagram_caption || ''),
			youtube_caption: String(c.youtube_caption || ''),
			hashtags: Array.isArray(c.hashtags) ? c.hashtags.slice(0, 10) : [],
		},
	});
}
return out;

const c = $input.item.json;
const start = c.start_sec;
const dur = c.duration_sec;
const base = `-i {{in_video}} -ss ${start} -t ${dur} `;
const enc = ` -c:v libx264 -preset fast -crf 23 -c:a aac -b:a 128k -movflags +faststart`;
return {
	json: {
		...c,
		tiktok_cmd: base + `-vf "crop=ih*9/16:ih,scale=1080:1920"` + enc + ` {{out_tiktok}}`,
		reels_cmd: base + `-vf "crop=ih*4/5:ih,scale=1080:1350"` + enc + ` {{out_reels}}`,
		square_cmd: base + `-vf "crop=ih:ih,scale=1080:1080"` + enc + ` {{out_square}}`,
		out_tiktok_name: `${c.id}_tiktok_1080x1920.mp4`,
		out_reels_name: `${c.id}_reels_1080x1350.mp4`,
		out_square_name: `${c.id}_square_1080x1080.mp4`,
	},
};

